use warnings;
use List::Util 'sort';

sub modify_and_sort {
    my ($s, $target, $key_char, $sub_str) = @_;

    $s =~ s/[^\w\s]//g; 
    my @words = split / /, $s;
    @words = grep { $_ ne $target } @words;   
    @words = map { scalar reverse $_ } @words;   
