import java.util.Arrays;

public class Permutation {

    public static void permute(int[] arr, int index, int n) {
        if (index >= n) {
            System.out.println(Arrays.toString(arr));
            return;
        }

        for (int i = index; i < n; i++) { 

            // Swapping
            int temp = arr[i];
            arr[i] = arr[index];
            arr[index] = temp;

            permute(arr, index + 1, n);

            // Backtrack
            temp = arr[i];
            arr[i] = arr[index];
            arr[index] = temp;
        }
    }

    public static void main(String[] args) {
        int[] arr = {1, 2, 3};
        permute(arr, 0, arr.length);
    }
}

