#include<stdio.h> 

// Function to calculate the sum of first n natural numbers 
int getSum(int n) 
{ 
	int sum = 0; 

	for (int i = 1; i <= n; ++i) 
		sum += i; 

	return sum; 
} 

int main() 
{ 
	int n = 10; 
	printf("Sum of first %d natural numbers is %d", 
								n, getSum(n)); 
	return 0; 
}
